class Calc {
  constructor() {
    this.m_value = 0;
  }

  add(value) {
    this.m_value += value;
    return this;
  }

  sub(value) {
    this.m_value -= value;
    return this;
  }

  mult(value) {
    this.m_value *= value;
    return this;
  }

  getValue() {
    return this.m_value;
  }
};

const calc = new Calc();
calc.add(5).sub(3).mult(4);
console.log(`The value is: ${calc.getValue()}`);
